import { useState, useCallback } from "react";
import {
  useWalletClient,
  usePublicClient,
  useAccount,
  useChainId,
} from "wagmi";
import { parseUnits } from "viem";

export type DeployStep =
  | "idle"
  | "deploying"
  | "confirming"
  | "done"
  | "error";

export interface DeployTokenInput {
  name: string;
  symbol: string;
  decimals: number;
  initialSupply: string; // human-readable, e.g. "1000000"
}

export interface DeployTokenResult {
  address: `0x${string}`;
  name: string;
  symbol: string;
  decimals: number;
  initialSupply: string;
  txHash: `0x${string}`;
}

// TestToken compiled bytecode (solmate ERC20 + faucet)
const TEST_TOKEN_BYTECODE =
  "" as `0x${string}`;

const TEST_TOKEN_ABI = [
  {
    type: "constructor",
    inputs: [
      { name: "name_", type: "string" },
      { name: "symbol_", type: "string" },
      { name: "decimals_", type: "uint8" },
      { name: "initialSupply", type: "uint256" },
    ],
    stateMutability: "nonpayable",
  },
] as const;

export function useDeployToken() {
  const { address } = useAccount();
  const chainId = useChainId();
  const { data: walletClient } = useWalletClient();
  const publicClient = usePublicClient();

  const [step, setStep] = useState<DeployStep>("idle");
  const [error, setError] = useState<Error | null>(null);
  const [result, setResult] = useState<DeployTokenResult | null>(null);

  const deploy = useCallback(
    async (input: DeployTokenInput) => {
      if (!walletClient || !publicClient || !address) {
        setError(new Error("Wallet not connected."));
        setStep("error");
        return;
      }

      // Only allow on testnets
      if (chainId !== 84532 && chainId !== 31337) {
        setError(new Error("Token deployment is only available on testnet."));
        setStep("error");
        return;
      }

      setStep("deploying");
      setError(null);
      setResult(null);

      try {
        const supplyWei = parseUnits(input.initialSupply, input.decimals);

        const hash = await walletClient.deployContract({
          abi: TEST_TOKEN_ABI,
          bytecode: TEST_TOKEN_BYTECODE,
          args: [input.name, input.symbol, input.decimals, supplyWei],
          gas: 2_000_000n,
        });

        setStep("confirming");

        const receipt = await publicClient.waitForTransactionReceipt({ hash });

        if (receipt.status === "reverted") {
          throw new Error(
            `Transaction reverted on-chain (tx: ${hash}). Check your wallet has enough ETH for gas.`
          );
        }

        if (!receipt.contractAddress) {
          throw new Error("Contract deployment failed — no address returned.");
        }

        setResult({
          address: receipt.contractAddress,
          name: input.name,
          symbol: input.symbol,
          decimals: input.decimals,
          initialSupply: input.initialSupply,
          txHash: hash,
        });
        setStep("done");
      } catch (err) {
        setError(err instanceof Error ? err : new Error(String(err)));
        setStep("error");
      }
    },
    [walletClient, publicClient, address, chainId],
  );

  const reset = useCallback(() => {
    setStep("idle");
    setError(null);
    setResult(null);
  }, []);

  return {
    step,
    error,
    result,
    deploy,
    reset,
    isActive: step === "deploying" || step === "confirming",
  };
}
